void SetTextMode()

{

   Text_Holder.StopSynchroText(0);

   Text_Holder.SetTextOffsets(0,0,0);



   curP = -1;



   Transparent_Video_Holder.Stop();

   if(textMode==0)

   {

      DisableScreen();

      int index = 0;

      while( index < 16 )

      {

         Bitmap_Holder.HideBitmap(index);

         index++;

      }

      EnableScreen();

      ShowBuffer();

      playStatus = 0;

      Sound_Holder.Stop(0);

      Text_Holder.HideText(0);

      Text_Holder.PlaySynchroText(0);

   }

   else

   {

      DisableScreen();

      Text_Holder.DisableMouse(0);

      int index = 0;

      Text_Holder.ShowText(0);

      while( index < 16 )

      {

         Bitmap_Holder.ShowBitmap(index);

         index++;

      }

      EnableScreen();

      ShowBuffer();

      playStatus = 1;   

      Sound_Holder.PlayDSound(0);

   }

}







void HotSpot_Holder.LeftButtonClickOn(int rectID)

{

   if(curP<15)   return;

   Transparent_Video_Holder.Play(rectID,0);

}





void HotSpot_Holder.MouseMoveIn(int rectID)

{

   if(curP<15)   return;

   SetCursor(1);

}





void HotSpot_Holder.MouseMoveOut(int rectID)

{

   if(curP<15)   return;

   SetCursor(0);

}





void Text_Holder.PlayMark(int textID,int markNo)

{

   if( textMode ) return;

   int olP=curP;

   switch(markNo)

   {

      case 3:

      case 4:

      case 5:

      case 6:

      case 7:

      case 9:

      case 11:

      case 32:

      case 33:

      case 34:

      case 35:

      case 36:

      case 37:

      case 38:

      case 39:

      case 41:

         curP++;

         break;

   }

   if(olP!=curP)  Bitmap_Holder.ShowBitmap(curP);

}





void Text_Holder.EndOfSynchroText(int textID)

{

   if( textMode ) return;

   playStatus=0;

   Transparent_Video_Holder.Play(15,0);

}





